<template><div><div class="page-title">通知消息</div><div class="page-card"><div class="toolbar"><el-button type="primary" @click="loadData">刷新</el-button><el-button type="success" @click="readAll">全部已读</el-button><el-tag>未读：{{ unread }}</el-tag></div><el-table :data="records" v-loading="loading" border><el-table-column prop="id" label="ID" width="80"/><el-table-column prop="title" label="标题" min-width="180"/><el-table-column prop="content" label="内容" min-width="260"/><el-table-column label="状态" width="100"><template #default="{row}"><el-tag :type="Number(row.readStatus)===1?'success':'warning'">{{ Number(row.readStatus)===1?'已读':'未读' }}</el-tag></template></el-table-column><el-table-column label="操作" width="120"><template #default="{row}"><el-button size="small" @click="readOne(row)">已读</el-button></template></el-table-column></el-table><el-pagination style="margin-top:16px" background layout="total, prev, pager, next, sizes" :total="total" v-model:current-page="query.pageNo" v-model:page-size="query.pageSize" @current-change="loadData" @size-change="loadData"/></div></div></template>
<script setup>import { reactive,ref,onMounted } from 'vue';import { ElMessage } from 'element-plus';import { pageMyNotices,markRead,markAllRead,countUnread } from '../api/notice';const loading=ref(false),records=ref([]),total=ref(0),unread=ref(0);const query=reactive({pageNo:1,pageSize:10});async function loadUnread(){unread.value=await countUnread()}async function loadData(){loading.value=true;try{const data=await pageMyNotices(query);records.value=data?.records||[];total.value=data?.total||0;await loadUnread()}finally{loading.value=false}}async function readOne(row){await markRead(row.id);ElMessage.success('已标记为已读');loadData()}async function readAll(){await markAllRead();ElMessage.success('已全部标记为已读');loadData()}onMounted(loadData)</script>
